assert ContainsAllShaded(grid, top, bottom, left, right) by {
  forall r: int | 0 <= r < |grid|
    ensures forall c: int {:trigger grid[r][c]} | 0 <= c < |grid[r]| :: (grid[r][c] == '*' ==> top <= r) && (grid[r][c] == '*' ==> r < bottom) && (grid[r][c] == '*' ==> left <= c) && (grid[r][c] == '*' ==> c < right)
  {
    assert |grid[r]| == m;
    forall c: int | 0 <= c < |grid[r]|
      ensures grid[r][c] == '*' ==> top <= r < bottom && left <= c < right
    {
      if grid[r][c] == '*' {
        if r < top {
          assert false;
        }
        if r >= bottom {
          assert r > bot;
          assert false;
        }
        if c < left {
          assert false;
        }
        if c >= right {
          assert c > ri;
          assert c < m;
          assert false;
        }
      }
    }
  }
}

assert exists c: int {:trigger grid[top][c]} | left <= c < right :: grid[top][c] == '*' by {
  ghost var c0 :| 0 <= c0 < |grid[top]| && grid[top][c0] == '*';
  assert left <= c0 < right;
}

assert exists c: int | left <= c < right :: grid[bottom - 1][c] == '*' by {
  ghost var c0 :| 0 <= c0 < |grid[bot]| && grid[bot][c0] == '*';
  assert left <= c0 < right;
}

assert exists r: int {:trigger grid[r]} | top <= r < bottom :: grid[r][left] == '*' by {
  ghost var r0 :| 0 <= r0 < n && grid[r0][left] == '*';
  assert top <= r0 < bottom;
}

assert exists r: int {:trigger grid[r]} | top <= r < bottom :: grid[r][right - 1] == '*' by {
  ghost var r0 :| 0 <= r0 < n && grid[r0][ri] == '*';
  assert top <= r0 < bottom;
}

assert forall r: int {:trigger grid[r]} | top <= r < bottom :: right <= |grid[r]| by {
  forall r: int | top <= r < bottom
    ensures right <= |grid[r]|
  {
    assert |grid[r]| == m;
  }
}
